const body = $input.first().json.body || $input.first().json;
const weekStartDate = body.weekStartDate || new Date().toISOString().split('T')[0];
const businessContext = body.businessContext || 'A solo service provider business';

const prompt = `You are a content strategist creating a 7-day content plan.

Business context:
${businessContext}

Week starting: ${weekStartDate}

Create 7 days of content that speaks directly to this specific business and its audience. Each day should have a distinct angle — do not repeat themes. Make the content feel human, specific, and useful — not generic.

For each day generate:
1. A topic that is relevant to this business specifically
2. An Instagram caption (engaging, with 3-5 hashtags specific to this industry, under 150 words)
3. A LinkedIn post (thought leadership tone, 150-200 words, no hashtags, professional)
4. A blog opener paragraph (hooks the reader, 70-90 words, informative)
5. A short-form video script (30-60 seconds when spoken aloud, conversational, for Reels/TikTok/Shorts)

Return ONLY valid JSON in this exact format:
{
  "posts": [
    {
      "content_date": "YYYY-MM-DD",
      "day_number": 1,
      "topic": "Topic title",
      "instagram_caption": "Caption with #hashtags",
      "linkedin_post": "LinkedIn post text",
      "blog_opener": "Blog opening paragraph",
      "video_script": "Hook line. [pause] Body. [pause] Call to action.",
      "tags": ["tag1", "tag2"],
      "status": "Generated"
    }
  ]
}

Generate all 7 days starting from ${weekStartDate}. Each day must be unique in angle and format.`;

return [{ json: { prompt, weekStartDate } }];

const raw = $input.first().json.message?.content || $input.first().json.content || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { posts: [] };
}
return [{ json: parsed }];
